async function validateInternalRequest(request, env) {
  const internalAuth = request.headers.get('X-Internal-Auth');
  
  if (!internalAuth) {
    return false;
  }
  
  const [timestamp, hash] = internalAuth.split(':');
  
  if (!timestamp || !hash) {
    return false;
  }
  
  const requestTime = parseInt(timestamp, 10);
  const currentTime = Date.now();
  
  if (currentTime - requestTime > 60000) {
    return false;
  }
  
  const secret = env.INTERNAL_SECRET || 'default-secret-change-in-production';
  const data = `${timestamp}:${secret}`;
  
  const encoder = new TextEncoder();
  const dataBuffer = encoder.encode(data);
  const hashBuffer = await crypto.subtle.digest('SHA-256', dataBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  const expectedHash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  
  return hash === expectedHash;
}

async function verifyToken(token, env) {
  try {
    const [header, payload, signature] = token.split('.');
    
    if (!header || !payload || !signature) {
      return null;
    }
    
    const secret = env.JWT_SECRET || 'jwt-secret-change-in-production';
    const dataToVerify = `${header}.${payload}`;
    
    const encoder = new TextEncoder();
    const dataBuffer = encoder.encode(dataToVerify + secret);
    const hashBuffer = await crypto.subtle.digest('SHA-256', dataBuffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const expectedSignature = btoa(String.fromCharCode(...hashArray)).replace(/=/g, '');
    
    if (signature !== expectedSignature) {
      return null;
    }
    
    const decodedPayload = JSON.parse(atob(payload));
    
    if (decodedPayload.exp && decodedPayload.exp < Date.now() / 1000) {
      return null;
    }
    
    return {
      userId: decodedPayload.sub,
      username: decodedPayload.username,
      roles: decodedPayload.roles || []
    };
    
  } catch (error) {
    return null;
  }
}

async function authenticateUser(username, password, env) {
  const users = {
    'admin': { id: '1', username: 'admin', passwordHash: 'hashed_password_1', roles: ['admin', 'user'] },
    'user': { id: '2', username: 'user', passwordHash: 'hashed_password_2', roles: ['user'] }
  };
  
  const user = users[username];
  
  if (!user) {
    return null;
  }
  
  return user;
}

async function generateUserToken(user, env) {
  const header = btoa(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).replace(/=/g, '');
  const payload = btoa(JSON.stringify({
    sub: user.id,
    username: user.username,
    roles: user.roles,
    iat: Math.floor(Date.now() / 1000),
    exp: Math.floor(Date.now() / 1000) + 3600
  })).replace(/=/g, '');
  
  const secret = env.JWT_SECRET || 'jwt-secret-change-in-production';
  const dataToSign = `${header}.${payload}`;
  
  const encoder = new TextEncoder();
  const dataBuffer = encoder.encode(dataToSign + secret);
  const hashBuffer = await crypto.subtle.digest('SHA-256', dataBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  const signature = btoa(String.fromCharCode(...hashArray)).replace(/=/g, '');
  
  return `${header}.${payload}.${signature}`;
}

